def merge_playlists(playlist1, playlist2):
    set1 = set(playlist1)
    set2 = set(playlist2)
    shared = sorted(set1 & set2)
    all_songs = sorted(set1 | set2)
    return {"shared": shared, "all_songs": all_songs}

unit_tests:
import unittest

class TestSolution(unittest.TestCase):
    def test_basic_overlap(self):
        result = merge_playlists(["SongA", "SongB", "SongC"], ["SongB", "SongC", "SongD"])
        self.assertEqual(result, {"shared": ["SongB", "SongC"], "all_songs": ["SongA", "SongB", "SongC", "SongD"]})

    def test_no_overlap(self):
        result = merge_playlists(["SongA", "SongB"], ["SongC", "SongD"])
        self.assertEqual(result, {"shared": [], "all_songs": ["SongA", "SongB", "SongC", "SongD"]})

    def test_complete_overlap(self):
        result = merge_playlists(["SongA", "SongB"], ["SongA", "SongB"])
        self.assertEqual(result, {"shared": ["SongA", "SongB"], "all_songs": ["SongA", "SongB"]})

    def test_hidden_both_empty(self):
        result = merge_playlists([], [])
        self.assertEqual(result, {"shared": [], "all_songs": []})

    def test_hidden_one_empty(self):
        result = merge_playlists(["SongA"], [])
        self.assertEqual(result, {"shared": [], "all_songs": ["SongA"]})

    def test_hidden_duplicates_within_playlist(self):
        result = merge_playlists(["SongA", "SongA", "SongB"], ["SongB", "SongC"])
        self.assertEqual(result, {"shared": ["SongB"], "all_songs": ["SongA", "SongB", "SongC"]})

    def test_hidden_single_same_song(self):
        result = merge_playlists(["X"], ["X"])
        self.assertEqual(result, {"shared": ["X"], "all_songs": ["X"]})

    def test_hidden_larger_case(self):
        result = merge_playlists(["A", "B", "C", "D", "E"], ["C", "D", "E", "F", "G"])
        self.assertEqual(result, {"shared": ["C", "D", "E"], "all_songs": ["A", "B", "C", "D", "E", "F", "G"]})

if __name__ == '__main__':
    unittest.main()
